--
-- Table structure for table `inbound_orders`
--

DROP TABLE IF EXISTS `inbound_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inbound_orders` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `inbound_no` varchar(50) NOT NULL COMMENT '入库单号',
  `purchase_order_id` bigint DEFAULT NULL COMMENT '关联采购单ID',
  `warehouse_id` bigint NOT NULL COMMENT '仓库ID',
  `status` varchar(20) DEFAULT 'PENDING',
  `inbound_date` datetime DEFAULT NULL COMMENT '入库时间',
  `confirmed_by` varchar(50) DEFAULT NULL COMMENT '确认人',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `province` varchar(50) DEFAULT NULL,
  `city` varchar(50) DEFAULT NULL,
  `district` varchar(50) DEFAULT NULL,
  `detail_address` varchar(255) DEFAULT NULL,
  `warehouse_code` varchar(50) DEFAULT NULL,
  `contact_email` varchar(100) DEFAULT NULL,
  `logistics_company` varchar(100) DEFAULT NULL,
  `tracking_no` varchar(100) DEFAULT NULL,
  `shipped_at` datetime DEFAULT NULL,
  `expected_arrival` datetime DEFAULT NULL,
  `actual_arrival` datetime DEFAULT NULL,
  `confirmed_ip` varchar(255) DEFAULT NULL,
  `contact_name` varchar(255) DEFAULT NULL,
  `contact_phone` varchar(255) DEFAULT NULL,
  `deliverer` varchar(255) DEFAULT NULL,
  `deliverer_phone` varchar(255) DEFAULT NULL,
  `delivery_address` varchar(255) DEFAULT NULL,
  `logistics_fee` decimal(19,2) DEFAULT NULL,
  `plate_number` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `inbound_no` (`inbound_no`),
  KEY `purchase_order_id` (`purchase_order_id`),
  KEY `warehouse_id` (`warehouse_id`),
  KEY `idx_inbound_tracking_no` (`tracking_no`),
  KEY `idx_inbound_warehouse_code` (`warehouse_code`),
  CONSTRAINT `inbound_orders_ibfk_1` FOREIGN KEY (`purchase_order_id`) REFERENCES `purchase_orders` (`id`),
  CONSTRAINT `inbound_orders_ibfk_2` FOREIGN KEY (`warehouse_id`) REFERENCES `warehouses` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='入库单表';
/*!40101 SET character_set_client = @saved_cs_client */;

